import { toServerItemCommunityInfo, } from '../../../models/server/items/community/info.js';
import { handleError } from '../../error.js';
export const createServerItemCommunityInfoRouteHandler = (sonolus, group) => async ({ req, res, localize, ctx }) => {
    if (!group.community.infoHandler) {
        res.status(404).end();
        return;
    }
    const itemName = req.params.itemName;
    if (!itemName) {
        res.status(400).end();
        return;
    }
    const response = await group.community.infoHandler({ ...ctx, itemName });
    if (handleError(response, res, localize))
        return;
    res.json(toServerItemCommunityInfo(sonolus, localize, response, group.community.actions, group.community.comment.actions));
};
